mapper.select:
SELECT ct.id, ct.title, ct.course_id AS courseId, c.name AS courseName, ct.lesson_count AS lessonCount, ct.quantity, COALESCE(r.recordCount, 0) AS recordCount, ct.expire_days AS expireDays, ct.end_date AS endDate, ct.state, ct.edit_time AS editTime, u.name AS editorName FROM course_trial ct LEFT JOIN course c ON ct.course_id = c.id LEFT JOIN staff u ON ct.editor = u.id LEFT JOIN (SELECT trial_id, COUNT(*) AS recordCount FROM course_trial_record GROUP BY trial_id) r ON r.trial_id = ct.id
ct.deleted = 0
AND ct.title LIKE CONCAT('%', #{query.title}, '%')
AND ct.course_id = #{query.courseId}
AND ct.state = #{query.state}
ORDER BY ct.add_time DESC, ct.id DESC
